<!DOCTYPE html>
<html lang="id">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Login Mahasiswa - SiRuang-Elektro</title>
    <link href="https://cdn.jsdelivr.net/npm/bootstrap@5.3.0/dist/css/bootstrap.min.css" rel="stylesheet">
    <link href="https://cdn.jsdelivr.net/npm/bootstrap-icons@1.10.5/font/bootstrap-icons.css" rel="stylesheet">
    <link href="https://fonts.googleapis.com/css2?family=Poppins:wght@300;400;500;600;700;800&display=swap" rel="stylesheet">
    <style>
        * { margin:0; padding:0; box-sizing:border-box; }
        body {
            font-family: "Poppins", sans-serif;
            min-height: 100vh;
            background: url("data:image/png;base64,") center center / cover no-repeat fixed;
            position: relative;
            display: flex;
            flex-direction: column;
        }
        body::before {
            content:'';
            position:fixed;
            inset:0;
            background:rgba(220,53,69,0.55);
    z-index:-1;
}

        /* ── NAVBAR ── */
        .top-bar {
            position: relative; z-index: 10;
            padding: 14px 36px;
            display: flex; align-items: center; justify-content: space-between;
            background: rgba(0,0,0,0.18);
            backdrop-filter: blur(6px);
            border-bottom: 1px solid rgba(255,255,255,0.08);
        }
        .brand-group { display:flex; align-items:center; gap:14px; }
        .ft-badge {
            background: #8B0000;
            border: 2px solid #FFD600;
            border-radius: 6px;
            padding: 5px 10px;
            color: #FFD600; font-weight:800; font-size:13px; letter-spacing:1px;
        }
        .siruang-logo { display:flex; align-items:center; gap:10px; }
        .logo-img-circle {
            width:38px; height:38px; border-radius:50%; overflow:hidden;
            border:2px solid rgba(255,255,255,0.55); background:white; flex-shrink:0;
        }
        .logo-img-circle img { width:100%; height:100%; object-fit:cover; }
        .logo-text { color:white; font-weight:700; font-size:18px; line-height:1; }
        .logo-text .si { color:#FFD600; }
        .logo-text .sub { color:#FFD600; font-size:12px; font-weight:500; display:block; }
        .lead-text {
            color:rgba(255,255,255,0.65); font-size:12px;
            border-left:1px solid rgba(255,255,255,0.25); padding-left:12px; line-height:1.4;
        }
        .back-btn {
            color:rgba(255,255,255,0.8); text-decoration:none; font-size:13px;
            display:flex; align-items:center; gap:6px; transition:color 0.2s;
        }
        .back-btn:hover { color:#FFD600; }

        /* ── CENTER WRAPPER ── */
        .page-center {
            flex:1; position:relative; z-index:2;
            display:flex; align-items:center; justify-content:center;
            padding: 32px 20px;
        }

        /* ── CARD ── */
        .login-card {
            width:100%; max-width:440px;
            background:white;
            border-radius:20px;
            overflow:hidden;
            box-shadow: 0 32px 80px rgba(0,0,0,0.45);
        }

        /* Card top strip */
        .card-strip {
            background: linear-gradient(135deg, #DC3545, #8B0000);
            padding: 26px 32px 36px;
            text-align:center;
            position:relative;
        }
        .strip-logo {
            width:60px; height:60px; border-radius:50%;
            overflow:hidden; border:3px solid rgba(255,255,255,0.5);
            background:white; margin:0 auto 12px;
        }
        .strip-logo img { width:100%; height:100%; object-fit:cover; }
        .card-strip h2 {
            color:white; font-weight:800; font-size:21px; margin-bottom:3px;
        }
        .card-strip h2 .si { color:#FFD600; }
        .card-strip p { color:rgba(255,255,255,0.70); font-size:12px; margin:0; }

        /* floating icon circle at bottom of strip */
        .strip-icon {
            position:absolute; bottom:-22px; left:50%; transform:translateX(-50%);
            width:44px; height:44px; border-radius:50%;
            background:white; border:3px solid #DC3545;
            display:flex; align-items:center; justify-content:center;
            box-shadow: 0 4px 14px rgba(0,71,171,0.3);
        }
        .strip-icon i { color:#DC3545; font-size:20px; }

        /* Card body */
        .card-body-area {
            padding: 42px 32px 30px;
        }
        .section-label {
            text-align:center; font-size:14px; color:#888;
            font-weight:500; margin-bottom:22px;
        }

        /* Alert */
        .my-alert {
            border-radius:10px; padding:10px 14px;
            font-size:13px; margin-bottom:16px;
            display:flex; align-items:center; gap:8px;
        }
        .my-alert.success { background:#eafaf1; border:1px solid #28a745; color:#1a7a3a; }
        .my-alert.danger  { background:#ffeaea; border:1px solid #dc3545; color:#a71d2a; }

        /* Field */
        .f-label {
            font-size:11px; font-weight:700; letter-spacing:.9px;
            text-transform:uppercase; color:#444; display:block; margin-bottom:6px;
        }
        .f-group {
            display:flex; align-items:center;
            border:2px solid #e8edf5; border-radius:10px;
            overflow:hidden; margin-bottom:16px;
            transition: border-color .2s, box-shadow .2s;
        }
        .f-group:focus-within {
            border-color:#DC3545;
            box-shadow:0 0 0 3px rgba(220,53,69,.15);
        }
        .f-group.err { border-color:#dc3545; }
        .f-icon {
            padding:12px 13px; background:#fff1f2;
            border-right:1px solid #e8edf5;
            color:#DC3545; font-size:15px; flex-shrink:0;
        }
        .f-group input {
            border:none; outline:none; flex:1;
            padding:12px 13px;
            font-family:"Poppins",sans-serif; font-size:14px; color:#333;
        }
        .f-group input::placeholder { color:#bbb; }
        .err-msg { color:#dc3545; font-size:12px; margin-top:-10px; margin-bottom:12px; }

        /* Submit */
        .btn-submit {
            width:100%; border:none; border-radius:10px;
            background:linear-gradient(135deg,#DC3545,#8B0000);
            color:white; padding:13px;
            font-family:"Poppins",sans-serif; font-size:15px; font-weight:700;
            cursor:pointer; display:flex; align-items:center; justify-content:center; gap:9px;
            transition:all .2s; margin-top:4px;
        }
        .btn-submit:hover {
            background:linear-gradient(135deg,#ff4d6d,#b22222);
            transform:translateY(-1px);
            box-shadow:0 8px 24px rgba(220,53,69,.35);
        }

        /* Divider */
        .or-div {
            display:flex; align-items:center; gap:12px; margin:20px 0 16px;
        }
        .or-div hr { flex:1; border-color:#eee; margin:0; }
        .or-div span { font-size:12px; color:#bbb; }

        /* Links */
        .link-row { text-align:center; font-size:13px; color:#777; margin-bottom:9px; }
        .link-row a { font-weight:700; text-decoration:none; }
        .la { color:#DC3545; } .la:hover { text-decoration:underline; color:#8B0000; }
        .lr { color:#0047AB; } .lr:hover { text-decoration:underline; color:#003080; }

        @media(max-width:480px){
            .card-body-area{ padding:38px 22px 26px; }
            .top-bar{ padding:12px 18px; }
            .lead-text{ display:none; }
        }
    </style>
</head>
